import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{r as a,o as r,c,a as e,b as s,d as n,f as i}from"./app-f83986bb.js";const l={},h=i('<h1 id="protocol" tabindex="-1"><a class="header-anchor" href="#protocol" aria-hidden="true">#</a> protocol</h1><h2 id="websocket" tabindex="-1"><a class="header-anchor" href="#websocket" aria-hidden="true">#</a> websocket</h2><p>WebSocket 是 HTML5 的重要特性，它实现了基于浏览器的远程 socket，它使浏览器和服务器可以进行全双工通信， 许多浏览器（Firefox、Google Chrom e 和 Safari）都已对此做了支持。</p><p>在 WebSocket 出现之前，为了实现即时通信，采用的技术都是 “轮询”，即在特定的时间间隔内，由浏览器对服务器发出 HTTP Request， 服务器在收到请求后，返回最新的数据给浏览器刷新，“轮询” 使得浏览器需要对服务器不断发出请求，这样会占用大量带宽。</p><p>WebSocket 采用了一些特殊的报头，使得浏览器和服务器只需要做一个握手的动作，就可以在浏览器和服务器之间建立一条连接通道。且此连接会保持在活动状态 你可以使用 JavaScript 来向连接写入或从中接收数据，就像在使用一个常规的 TCP Socket 一样。它解决了 Web 实时化的问题，相比传统 HTTP 有如下好处：</p><ul><li>一个 Web 客户端只建立一个 TCP 连接</li><li>Websocket 服务端可以推送 (push) 数据到 web 客户端.</li><li>有更加轻量级的头，减少数据传送量</li></ul><p>WebSocket URL 的起始输入是 ws:// 或是 wss://（在 SSL 上）</p><p>WebSocket 的协议颇为简单，在第一次 handshake 通过以后，连接便建立成功，其后的通讯数据都是以 ”\\x00″ 开头，以 ”\\xFF” 结尾。在客户端，这个是透明的，WebSocket 组件会自动将原始数据 “掐头去尾”。</p><h2 id="kerberos认证协议" tabindex="-1"><a class="header-anchor" href="#kerberos认证协议" aria-hidden="true">#</a> kerberos认证协议</h2>',9),d={href:"https://blog.csdn.net/weixin_38233104/article/details/122963237",target:"_blank",rel:"noopener noreferrer"},p=e("p",null,"和Oauth2授权码认证类似，在通信过程加了密钥处理",-1);function _(b,k){const o=a("ExternalLinkIcon");return r(),c("div",null,[h,e("p",null,[e("a",d,[s("参考"),n(o)])]),p])}const x=t(l,[["render",_],["__file","协议.html.vue"]]);export{x as default};
